1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Damage = { itemType: string; amount: number };
18	type Incident = { cause: string; damages: Damage[] };
19	type QuoteStep = { op: "quote"; items: Item[] };
20	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
21	type Step = QuoteStep | ClaimStep;
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	type ItemTypeSpec = { basePremium: number; insuranceValue: number; isComponent: boolean };
26	
27	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
28	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
29	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
30	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
31	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
32	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
33	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
34	};
35	
36	const basePremiumFor = (item: Item): number => ITEM_TYPES[item.type].basePremium;
37	const insuranceValueFor = (item: Item): number => ITEM_TYPES[item.type].insuranceValue;
38	
39	const countByType = (items: Item[]): Map<string, number> => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return counts;
45	};
46	
47	const premiumForTypeCount = (type: string, count: number): number => {
48	  const spec = ITEM_TYPES[type];
49	  return spec.isComponent && count === BLOCK_SIZE
50	    ? BLOCK_PREMIUM
51	    : count * spec.basePremium;
52	};
53	
54	const basePremiumOf = (items: Item[]): number => {
55	  let total = 0;
56	  for (const [type, count] of countByType(items)) {
57	    total += premiumForTypeCount(type, count);
58	  }
59	  return total;
60	};
61	
62	type SurchargeRule = { applies: (item: Item) => boolean; rate: number };
63	
64	const SURCHARGE_RULES: SurchargeRule[] = [
65	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
66	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
67	];
68	
69	const surchargeRateFor = (item: Item): number =>
70	  SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
71	
72	const itemSurchargesOf = (items: Item[]): number =>
73	  items.reduce((sum, item) => sum + basePremiumFor(item) * surchargeRateFor(item), 0);
74	
75	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
76	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
77	    ? basePremium * LOYALTY_DISCOUNT_RATE
78	    : 0;
79	
80	const followUpDiscountFor = (basePremium: number, stepIndex: number): number =>
81	  stepIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
82	
83	const quoteForStep = ({ items }: QuoteStep, customer: Customer, stepIndex: number) => {
84	  const basePremium = basePremiumOf(items);
85	  const itemSurcharges = itemSurchargesOf(items);
86	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
87	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
88	  const followUpDiscount = followUpDiscountFor(basePremium, stepIndex);
89	  return {
90	    premium: Math.ceil(
91	      basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
92	    ),
93	  };
94	};
95	
96	type Policy = { items: Item[]; remainingCap: number };
97	
98	const policyFor = (items: Item[]): Policy => {
99	  const insuranceSum = items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
100	  return { items, remainingCap: insuranceSum * CAP_MULTIPLIER };
101	};
102	
103	const insuredItemFor = (policy: Policy, damage: Damage): Item =>
104	  policy.items.find((item) => item.type === damage.itemType)!;
105	
106	const reimbursementRateFor = (item: Item): number =>
107	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
108	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
109	    : 1;
110	
111	const payoutForDamage = (policy: Policy, damage: Damage): number => {
112	  const item = insuredItemFor(policy, damage);
113	  return damage.amount * reimbursementRateFor(item) - DEDUCTIBLE;
114	};
115	
116	const validateDamages = (policy: Policy, damages: Damage[]): void => {
117	  const insuredCounts = countByType(policy.items);
118	  const damageCounts = new Map<string, number>();
119	  for (const damage of damages) {
120	    if (!insuredCounts.has(damage.itemType)) {
121	      throw new Error(`Damaged item not insured: ${damage.itemType}`);
122	    }
123	    if (damage.amount < 0) {
124	      throw new Error(`Negative damage amount: ${damage.amount}`);
125	    }
126	    const next = (damageCounts.get(damage.itemType) ?? 0) + 1;
127	    if (next > insuredCounts.get(damage.itemType)!) {
128	      throw new Error(`Too many damages for: ${damage.itemType}`);
129	    }
130	    damageCounts.set(damage.itemType, next);
131	  }
132	};
133	
134	const claimForStep = (step: ClaimStep, policies: Map<number, Policy>) => {
135	  const policy = policies.get(step.policy)!;
136	  validateDamages(policy, step.incident.damages);
137	  const desiredPayout = step.incident.damages.reduce((sum, dmg) => sum + payoutForDamage(policy, dmg), 0);
138	  const payout = Math.floor(Math.min(desiredPayout, policy.remainingCap));
139	  policy.remainingCap -= payout;
140	  return { payout, remainingCap: policy.remainingCap };
141	};
142	
143	const validateItems = (items: Item[]): void => {
144	  for (const item of items) {
145	    if (!(item.type in ITEM_TYPES)) {
146	      throw new Error(`Unknown item type: ${item.type}`);
147	    }
148	  }
149	};
150	
151	export const runScenario = (scenario: Scenario): unknown => {
152	  const policies = new Map<number, Policy>();
153	  const results = scenario.steps.map((step, i) => {
154	    if (step.op === "quote") {
155	      validateItems(step.items);
156	      policies.set(i, policyFor(step.items));
157	      return quoteForStep(step, scenario.customer, i);
158	    }
159	    return claimForStep(step, policies);
160	  });
161	  return { results };
162	};
